// Context Handling Tests
// ====================================================================================

func TestComponent_RespectsContext_Cancellation(t *testing.T) {
	t.Skip("requires real NATS connection - move to integration tests")
	comp := createTestComponentWithMockKV(t)
	ctx, cancel := context.WithCancel(context.Background())

	require.NoError(t, comp.Initialize())
	require.NoError(t, comp.Start(ctx))

	// Cancel context
	cancel()

	// Allow time for cancellation to propagate
	time.Sleep(100 * time.Millisecond)

	// Component should handle cancellation gracefully
	err := comp.Stop(1 * time.Second)
	assert.NoError(t, err)
}

func TestComponent_RespectsContext_Timeout(t *testing.T) {
	comp := createTestComponentWithMockKV(t)
	ctx, cancel := context.WithTimeout(context.Background(), 100*time.Millisecond)
	defer cancel()

	require.NoError(t, comp.Initialize())

	// Start with timeout context
	err := comp.Start(ctx)

	// Should either succeed or handle timeout gracefully
	if err != nil {
		// If error, it should be context-related
		assert.Contains(t, err.Error(), "context")
	}
}

func TestComponent_ContextCancellation_StopsIndexing(t *testing.T) {
	comp := createTestComponentWithMockKV(t)
	ctx, cancel := context.WithCancel(context.Background())

	// Cancel immediately
	cancel()

	// Operations should respect cancelled context
	err := comp.UpdateOutgoingIndex(ctx, "entity", "target", "predicate")

	assert.Error(t, err, "should fail with cancelled context")
}

// ====================================================================================
// Concurrent Operations Tests
// ====================================================================================

func TestComponent_ConcurrentIndexUpdates_NoDataRace(t *testing.T) {
	comp := createTestComponentWithMockKV(t)
	ctx := context.Background()

	// Run concurrent index updates
	const numGoroutines = 10
	const numOpsPerGoroutine = 100

	done := make(chan bool)
	for i := 0; i < numGoroutines; i++ {
		go func(id int) {
			for j := 0; j < numOpsPerGoroutine; j++ {
				entityID := "entity-" + string(rune(id))
				targetID := "target-" + string(rune(j))
				_ = comp.UpdateOutgoingIndex(ctx, entityID, targetID, "predicate")
			}
			done <- true
		}(i)
	}

	// Wait for all goroutines
	for i := 0; i < numGoroutines; i++ {
		<-done
	}

	// No assertions needed - test passes if no data race detected by race detector
}

func TestComponent_ConcurrentHealthChecks_ThreadSafe(t *testing.T) {
	comp := createTestComponent(t)

	// Run concurrent health checks
	const numGoroutines = 50

	done := make(chan bool)
	for i := 0; i < numGoroutines; i++ {
		go func() {
			for j := 0; j < 100; j++ {
				_ = comp.Health()
				_ = comp.DataFlow()
			}
			done <- true
		}()
	}

	// Wait for all goroutines
	for i := 0; i < numGoroutines; i++ {
		<-done
	}

	// No assertions needed - test passes if no data race detected
}

