func TestComponent_MetricsUpdate_OnIndexOperation(t *testing.T) {
	comp := createTestComponentWithMockKV(t)
	ctx := context.Background()

	initialMetrics := comp.DataFlow()
	initialActivity := initialMetrics.LastActivity

	// Wait to ensure time difference
	time.Sleep(10 * time.Millisecond)

	// Perform operation
	err := comp.UpdateOutgoingIndex(ctx, "entity", "target", "predicate")
	require.NoError(t, err)

	// Check metrics updated
	updatedMetrics := comp.DataFlow()
	assert.True(t, updatedMetrics.LastActivity.After(initialActivity), "LastActivity should update after operation")
}

